        if (!string.IsNullOrWhiteSpace(request.GuestEmail))
        {
            existing = await _dbContext.Rsvps
                .FirstOrDefaultAsync(
                    r => r.EventId == link.EventId && r.GuestEmail == request.GuestEmail,
                    cancellationToken);
        }

        Rsvp rsvp;
        if (existing is not null)
        {
            existing.GuestName = request.GuestName;
            existing.Status = request.Status;
            existing.Note = request.Note;
            existing.UpdatedAt = now;
            existing.IpAddress = TruncateIp(request.IpAddress);
            rsvp = existing;
        }
        else
        {
            rsvp = new Rsvp
            {
                Id = Guid.NewGuid(),
                EventId = link.EventId,
                InviteLinkId = link.Id,
                GuestName = request.GuestName,
                GuestEmail = string.IsNullOrWhiteSpace(request.GuestEmail) ? null : request.GuestEmail,
                Status = request.Status,
                Note = request.Note,
                RespondedAt = now,
                UpdatedAt = null,
