            rsvp.GuestName,
            rsvp.Status,
            link.Event.Title,
            link.Event.StartDate);
    }

    /// <summary>Truncates the captured IP to the column length (45 chars covers IPv6).</summary>
    private static string? TruncateIp(string? ip)
    {
        if (string.IsNullOrWhiteSpace(ip))
        {
            return null;
        }

        return ip.Length <= 45 ? ip : ip[..45];
    }
